<template>
  <div class="login-container">
    <!-- 用户信息 -->
    <el-row
      type="flex"
      justify="space-between"
      style="align-items: center; flex-wrap: nowrap; overflow: hidden; width: 100%; background-color: black"
    >
      <el-col :span="16" style="overflow: hidden; white-space: nowrap; text-overflow: ellipsis; min-width: 0"
        ><span v-if="headerConfig && headerConfig.account">{{ userInfo.account }}</span
        ><span v-if="headerConfig && headerConfig.member">【{{ memberVipLevel }}】</span>
        <span
          v-if="headerConfig && headerConfig.version && currentVersion"
          style="cursor: pointer; font-size: 14px"
          @click="openBrowser(versionHistoryUrl)"
          >Beta v{{ currentVersion }}</span
        ></el-col
      >
      <el-col :span="8" style="text-align: right; white-space: nowrap; flex-shrink: 0; padding-right: 10px">
        <span v-if="headerConfig && headerConfig.recharge" style="cursor: pointer" @click="handleRecharge">充值</span>
        <span v-if="headerConfig && headerConfig.setting" style="cursor: pointer" @click="handleSetting">设置</span>
        <span style="cursor: pointer" @click="userExit">退出</span></el-col
      >
    </el-row>
    <!-- 新版本提示 -->
    <el-row :gutter="10" v-if="lasterVersion && currentVersion && currentVersion !== lasterVersion">
      <el-col :span="24">
        <el-alert type="success" :center="false">
          <template v-slot:title>
            <span style="color: red; cursor: pointer" @click="openBrowser(versionHistoryUrl)"
              >最新版本已更新到 Beta v{{ lasterVersion }}，点击更新</span
            >
          </template>
        </el-alert>
      </el-col>
    </el-row>

    <!-- 顶部长图 -->
    <el-row>
      <el-col :span="24">
        <el-image v-if="headerImage" :src="headerImage" @click="openBrowser(versionHistoryUrl)" style="height: 125px; cursor: pointer; width: 100%" />
        <el-empty v-else description="暂无内容" style="height: 125px; cursor: pointer; width: 100%; background: black"></el-empty>
      </el-col>
    </el-row>

    <!-- 导航栏 -->
    <el-row type="flex" justify="space-between">
      <el-col>
        <el-menu
          style="height: 38px"
          :default-active="activePage"
          mode="horizontal"
          background-color="black"
          text-color="#fff"
          active-text-color="#F1951C"
        >
          <el-menu-item @click="jump(item.pageSign)" style="height: 38px" v-for="item in menuList" :key="item.pageSign" :index="item.pageSign">{{
            item.title
          }}</el-menu-item>
        </el-menu>
      </el-col>
    </el-row>

    <!-- 页面内容区，根据 page 切换 -->
    <el-row type="flex" justify="space-between">
      <el-col>
        <component
          ref="currentComponentRef"
          :categoryParentId="categoryParentId"
          :is="currentPageComponent"
          :vipPackageList="vipPackageList"
          :localMaterialImg="localMaterialImg"
          :lasterVersion="lasterVersion"
          :currentVersion="currentVersion"
          @refreshUserInfo="refreshUserInfo"
          @handleRecharge="handleRecharge"
        />
      </el-col>
    </el-row>

    <!-- 强制更新 -->
    <VersionUpdate ref="versionUpdateRef" :forceUpdate="forceUpdate" :lasterVersion="lasterVersion" :currentVersion="currentVersion" />

    <!-- 海报 -->
    <Poster ref="posterRef" :posterStatus="posterStatus" :posterUrl="posterUrl" />

    <!-- 充值弹窗 -->
    <RechargeDialog ref="rechargeDialogRef" @refreshUserInfo="refreshUserInfo" />

    <!-- 设置弹窗 -->
    <SettingDialog ref="settingDialogRef" @refreshLocalFile="refreshUserInfo" />
  </div>
</template>

<script>
import AddMaterial from '@/views/templateone/AddMaterial.vue';
import LocalMaterial from '@/views/templateone/LocalMaterial.vue';
import PsdFile from '@/views/templateone/PsdFile.vue';
import MoreService from '@/views/templateone/MoreService.vue';
import ImportFile from '@/views/templateone/ImportFile.vue';
import SourceFile from '@/views/templateone/SourceFile.vue';
import RechargeDialog from '@/components/RechargeDialog.vue';
import SettingDialog from '@/components/SettingDialog.vue';
import Poster from '@/components/Poster.vue';
import VersionUpdate from '@/components/VersionUpdate.vue';
import MaterialList from '@/views/templatetwo/MaterialList.vue';
import LocalMaterialTwo from '@/views/templatetwo/LocalMaterialTwo.vue';
import BatchProcess from '@/views/templatetwo/BatchProcess.vue';
import { getMemUserInfo, getLatestVersion, getMultiConfig } from '@/api/main';
import { getToken, removeToken } from '@/utils/auth';
import { startCepSpy, getPluginVersion } from '@/utils/cepspy';
import { toBoolean } from '@/utils/common';
import { openExternalLink } from '@/utils/cepInterface';

export default {
  name: 'Main',
  components: {
    AddMaterial,
    LocalMaterial,
    PsdFile,
    MoreService,
    ImportFile,
    SourceFile,
    RechargeDialog,
    SettingDialog,
    Poster,
    VersionUpdate,
    MaterialList,
    LocalMaterialTwo,
    BatchProcess
  },
  data() {
    return {
      headerConfig: {},
      userInfo: {},
      menuList: [
        { title: '添加素材', pageSign: 'AddMaterial', categoryId: 9, defaultShow: true },
        { title: '本地素材', pageSign: 'LocalMaterial', categoryId: 9 }
      ],
      activePage: 'AddMaterial', // 当前页面标识
      coinPackageList: [],
      rechargeHeaderStatus: false,
      rechargeHeaderImg: null,
      headerImage: null,
      versionHistoryUrl: null,
      vipPackageList: [],
      posterStatus: false,
      posterUrl: null,
      forceUpdate: false,
      currentVersion: null,
      lasterVersion: null,
      categoryParentId: '',
      localMaterialImg: null
    };
  },
  mounted() {
    startCepSpy();
  },
  computed: {
    memberVipLevel() {
      if (this.userInfo && this.userInfo.level) {
        const item = this.vipPackageList.find((item) => item.id === this.userInfo.level);
        return item ? item.name : '普通用户';
      }
      return '普通用户';
    },
    currentPageComponent() {
      // 根据 page 返回对应的子组件名
      // 例如 return 'AddMaterial'，需在 components 注册
      return this.currentComponent();
    }
  },
  created() {
    if (!getToken()) {
      this.userExit();
      return;
    }
    this.getUserInfo();
    this.getConfig();
  },
  methods: {
    currentComponent() {
      if (this.activePage) {
        this.categoryParentId = String(this.menuList.find((item) => item.pageSign === this.activePage).categoryId || '');
        return this.activePage;
      }
      return 'AddMaterial';
    },
    jump(val) {
      if (this.activePage === val) return;
      this.activePage = val;
    },
    getUserInfo() {
      // 获取用户信息
      getMemUserInfo().then((response) => {
        this.userInfo = response.data;
      });
    },
    getConfig() {
      let params = {
        codeList: [
          'sys.vipConfig',
          'sys.slideShow',
          'sys.versionHistoryUrl',
          'sys.recharge.config',
          'sys.recharge',
          'sys.poster',
          'sys.menulist',
          'sys.forcedUpdate',
          'sys.localMaterial.img',
          'sys.main.header'
        ]
      };
      // 获取配置信息
      Promise.all([getLatestVersion(), getMultiConfig(params)]).then(([versionInfo, multiConfig]) => {
        this.headerConfig = JSON.parse(multiConfig.data['sys.main.header']) || {};
        this.headerImage = multiConfig.data['sys.slideShow'] || '';
        this.menuList = JSON.parse(multiConfig.data['sys.menulist']) || this.menuList;
        this.activePage = this.menuList.find((item) => item.defaultShow === true).pageSign;

        this.forceUpdate = toBoolean(multiConfig.data['sys.forcedUpdate']);
        this.lasterVersion = versionInfo.data;
        this.currentVersion = getPluginVersion();
        this.versionHistoryUrl = multiConfig.data['sys.versionHistoryUrl'];
        let posterConfig = JSON.parse(multiConfig.data['sys.poster']) || {};
        this.posterStatus = toBoolean(posterConfig.status || false);
        this.posterUrl = posterConfig.url || '';
        this.vipPackageList = JSON.parse(multiConfig.data['sys.vipConfig']) || [];
        let rechargeConfig = JSON.parse(multiConfig.data['sys.recharge']) || {};
        this.rechargeHeaderStatus = toBoolean(rechargeConfig.status || false);
        this.rechargeHeaderImg = rechargeConfig.url || '';
        this.coinPackageList = JSON.parse(multiConfig.data['sys.recharge.config']) || [];
        this.localMaterialImg = multiConfig.data['sys.localMaterial.img'] || '';
      });
    },
    handleRecharge() {
      this.$refs.rechargeDialogRef.handleOpen(true, this.userInfo, this.rechargeHeaderStatus, this.rechargeHeaderImg, this.coinPackageList);
    },
    handleSetting() {
      this.$refs.settingDialogRef.handleOpen(true);
    },
    openBrowser(url) {
      // 打开外部链接
      if (url) {
        openExternalLink(url);
      }
    },
    userExit() {
      removeToken();
      this.$router.push({ name: 'Login' });
    },
    handleRefreshComponent() {
      // 当设置对话框提交后，如果当前是本地素材页面，则刷新它
      if (this.activePage === 'LocalMaterial') {
        this.$nextTick(() => {
          const componentRef = this.$refs.currentComponentRef;
          if (componentRef && componentRef.refreshLocalMaterial) {
            componentRef.refreshLocalMaterial();
          }
        });
      } else if (this.activePage === 'PsdFile') {
        this.$nextTick(() => {
          const componentRef = this.$refs.currentComponentRef;
          if (componentRef && componentRef.refreshPsdFile) {
            componentRef.refreshPsdFile();
          }
        });
      }
    },
    refreshUserInfo() {
      // 刷新用户信息
      this.getUserInfo();
      this.handleRefreshComponent();
    }
  }
};
</script>

<style scoped>
.login-container {
  background: #330505;
  color: white;
  overflow-x: hidden;
}
.el-menu--horizontal {
  display: flex !important;
  justify-content: space-between;
}
.el-menu--horizontal > .el-menu-item {
  height: 30px;
  line-height: 30px;
  flex: 1 1 0;
  text-align: center;
  padding: 0;
}

/deep/ .el-menu--horizontal > .el-menu-item.is-active {
  font-weight: bold;
  border-bottom: 3px solid #f1951c !important;
}
</style>
